tests.code:
var t = new Toggle();
t.flip();
assertEqual(t.isOn(), true);

var t = new Toggle();
t.flip();
t.flip();
assertEqual(t.isOn(), false);

var t = new Toggle(true);
assert(t.isOn() === true);
t.flip();
assert(t.isOn() === false);

var a = new Toggle(), b = new Toggle();
a.flip();
assert(a.isOn() === true && b.isOn() === false, 'b is untouched by a');

var acc = new Accumulator();
assert(acc.add(10) === 10, 'first add returns 10');
assert(acc.add(5) === 15, 'then 15');

var acc = new Accumulator();
acc.add(3);
acc.add(4);
assertEqual(acc.total(), 7);

var acc = new Accumulator();
acc.add(20);
assert(acc.add(-8) === 12, 'subtracting works too');

var a = new Accumulator(), b = new Accumulator();
a.add(100);
assert(b.total() === 0, 'b keeps its own total');

var inv = new Inventory();
inv.add('ammo');
assertEqual(inv.has('ammo'), true);

var inv = new Inventory();
inv.add('ammo');
assertEqual(inv.has('medkit'), false);

var inv = new Inventory();
inv.add('ammo');
inv.add('ammo');
inv.add('medkit');
assertEqual(inv.count(), 2);

var a = new Inventory(), b = new Inventory();
a.add('scrap');
assert(b.has('scrap') === false && b.count() === 0, 'b has its own hold');

var q = new Queue();
q.enqueue(1);
q.enqueue(2);
assert(q.dequeue() === 1, 'front first');
assert(q.dequeue() === 2, 'then the next');

var q = new Queue();
q.enqueue('a');
q.enqueue('b');
q.dequeue();
assertEqual(q.size(), 1);

var q = new Queue();
q.enqueue(7);
q.dequeue();
assert(q.dequeue() === null, 'empty again after draining');
q.enqueue(9);
assert(q.dequeue() === 9 && q.size() === 0);

var a = new Queue(), b = new Queue();
a.enqueue(1);
assert(b.size() === 0 && b.dequeue() === null, 'b has its own buffer');

var w = new Wallet(10);
w.deposit(5);
assertEqual(w.balance(), 15);

var a = new Wallet(100), b = new Wallet(0);
a.withdraw(50);
assert(b.balance() === 0, 'b keeps its own balance');
